import React from 'react';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faInstagram, faGithub } from '@fortawesome/free-brands-svg-icons';

const FooterSection = styled.footer`
  padding: 100px 10% 40px;
  position: relative;
  overflow: hidden;
`;

const Container = styled.div`
  max-width: 1200px;
  margin: auto;
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 60px;
  position: relative;
  z-index: 2;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
    gap: 40px;
  }
`;

const Logo = styled.div`
  h3 {
    font-family: 'Orbitron', sans-serif;
    font-size: 2.5rem;
    color: #00FFFF;
    margin-bottom: 25px;
  }

  p {
    color: rgba(255, 255, 255, 0.8);
    line-height: 1.8;
  }
`;

const Links = styled.div`
  h4 {
    color: #00FFFF;
    margin-bottom: 20px;
    font-size: 1.2rem;
  }

  ul {
    list-style: none;

    li {
      margin-bottom: 15px;

      a {
        color: rgba(255, 255, 255, 0.8);
        text-decoration: none;
        transition: color 0.3s ease;

        &:hover {
          color: #00FFFF;
        }
      }
    }
  }
`;

const Social = styled.div`
  h4 {
    color: #00FFFF;
    margin-bottom: 20px;
    font-size: 1.2rem;
  }

  .social-icons {
    display: flex;
    gap: 20px;

    a {
      color: #00FFFF;
      font-size: 1.5rem;
      transition: transform 0.3s ease;

      &:hover {
        transform: translateY(-5px);
      }
    }
  }
`;

const Bottom = styled.div`
  text-align: center;
  margin-top: 60px;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  color: rgba(255, 255, 255, 0.6);
`;

const Footer = () => {
  return (
    <FooterSection id="footer">
      <Container data-aos="fade-up">
        <Logo>
          <h3>OPTIMUS</h3>
          <p>
            Empowering students to innovate, collaborate, and lead. Join us on our mission 
            to make ideas reality through technology and community.
          </p>
        </Logo>

        <Links>
          <h4>Quick Links</h4>
          <ul>
            <li><a href="#mission">Mission</a></li>
            <li><a href="#events">Events</a></li>
            <li><a href="#team">Team</a></li>
            <li><a href="#contact">Contact</a></li>
          </ul>
        </Links>

        <Links>
          <h4>Resources</h4>
          <ul>
            <li><a href="#">Blog</a></li>
            <li><a href="#">Projects</a></li>
            <li><a href="#">Workshops</a></li>
            <li><a href="#">Gallery</a></li>
          </ul>
        </Links>

        <Social>
          <h4>Connect With Us</h4>
          <div className="social-icons">
            <a href="https://www.instagram.com/optimus.orgz/" target="_blank" rel="noopener noreferrer">
              <FontAwesomeIcon icon={faInstagram} />
            </a>
            <a href="https://github.com/optimusorgz" target="_blank" rel="noopener noreferrer">
              <FontAwesomeIcon icon={faGithub} />
            </a>
          </div>
        </Social>
      </Container>

      <Bottom data-aos="fade-up" data-aos-delay="100">
        <p>© 2025 Optimus Club. All rights reserved.</p>
      </Bottom>
    </FooterSection>
  );
};

export default Footer;
